//! Spec-compliance tests: Numbering Constraints (ISO 29500-1 §17.9, §17.3.1, §17.7.2)
//!
//! These tests verify numbering resolution semantics:
//!   - numId=0 removal of inherited numbering (§17.9.18)
//!   - pStyle reverse binding in numbering levels (§17.9.23)
//!   - direct numPr overriding style numPr (§17.3.1.19 / §17.7.2)
//!
//! Tests marked `#[ignore]` document known gaps — they encode the *correct*
//! spec behavior and are expected to fail against the current implementation.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/create_numbering_constraints.py`.

use stemma::{DocxRuntime, SimpleRuntime};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/numbering-constraints";

// ── numId=0 removal (§17.9.18) ──────────────────────────────────────────

/// ISO 29500-1 §17.9.18: numId=0 removes inherited numbering from a style.
///
/// The fixture has:
///   - Style "NumberedStyle" with numPr (numId=1, ilvl=0) pointing to bullets
///   - P2 uses "NumberedStyle" + direct numPr with numId="0"
///
/// Per §17.9.18: "If this element's val attribute is 0, then the paragraph
/// shall not have any numbering properties applied to it, regardless of any
/// numbering properties inherited from the paragraph's style."
///
/// P2 should have NO numbering info, even though its style provides numbering.
/// POSITIVE: numId=0 removal IS supported.
#[test]
fn spec_numid_zero_removes_inherited_numbering() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "numid-zero-removal");
    let paras = common::all_paragraphs(&doc);

    let p2 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("numId zero"))
        .expect("should find paragraph with 'numId zero' text");

    // Per §17.9.18: numId=0 means no numbering, regardless of style.
    assert!(
        p2.numbering.is_none(),
        "P2 has numId=0 and should have no numbering per §17.9.18, \
         but got {:?}",
        p2.numbering
    );
}

/// ISO 29500-1 §17.9.18: numId=0 on one paragraph does not affect siblings.
///
/// Paragraphs 1 and 3 use "NumberedStyle" without direct numPr override,
/// so they should still have numbering from the style.
#[test]
fn spec_numid_zero_does_not_affect_siblings() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "numid-zero-removal");
    let paras = common::all_paragraphs(&doc);

    let p1 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("inherited numbering from style"))
        .expect("should find P1 with 'inherited numbering from style' text");

    let p3 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("numbering restored"))
        .expect("should find P3 with 'numbering restored' text");

    assert!(
        p1.numbering.is_some(),
        "P1 should have numbering inherited from 'NumberedStyle' style. \
         Style has numPr (numId=1, ilvl=0)."
    );

    assert!(
        p3.numbering.is_some(),
        "P3 should have numbering inherited from 'NumberedStyle' style. \
         The numId=0 on P2 is local and should not affect P3."
    );
}

// ── pStyle reverse binding (§17.9.23) ───────────────────────────────────

/// ISO 29500-1 §17.9.23: pStyle in a numbering level binds a style to
/// that level. A paragraph using that style gets numbering even if the
/// style itself has no numPr.
///
/// The fixture has:
///   - abstractNum level 0 with <w:pStyle w:val="ListBullet"/>
///   - Style "ListBullet" with NO numPr
///   - P1 uses style "ListBullet" — should get numbering via reverse binding
///
/// This is likely unimplemented — reverse binding requires scanning all
/// abstractNum definitions for pStyle references during style resolution.
#[test]
fn spec_pstyle_reverse_binding_applies_numbering() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "pstyle-reverse-binding");
    let paras = common::all_paragraphs(&doc);

    let p1 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("reverse binding"))
        .expect("should find P1 with 'reverse binding' text");

    let p2 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Normal paragraph"))
        .expect("should find P2 normal paragraph");

    // P1 should get numbering from the abstract level's pStyle reference
    assert!(
        p1.numbering.is_some(),
        "P1 with style 'ListBullet' should get numbering from abstractNum \
         level 0's <w:pStyle w:val='ListBullet'/> reverse binding per §17.9.23."
    );

    // P2 (normal) should have no numbering
    assert!(
        p2.numbering.is_none(),
        "P2 (normal paragraph) should have no numbering, got {:?}",
        p2.numbering
    );
}

// ── Style numPr override (§17.3.1.19 / §17.7.2) ────────────────────────

/// ISO 29500-1 §17.3.1.19 (numPr in paragraph properties) / §17.7.2
/// (style hierarchy cascade): Direct numPr on a paragraph overrides the
/// numPr inherited from its style.
/// (§17.7.4.14 is qFormat — "Primary Style" — not numPr.)
///
/// The fixture has:
///   - numId=1 → bullets (abstractNum 0)
///   - numId=2 → decimal (abstractNum 1)
///   - Style "NumberedStyle" has numPr (numId=1, bullets)
///   - P1: uses "NumberedStyle" only — gets bullets from style
///   - P2: uses "NumberedStyle" + direct numPr (numId=2) — gets decimal
#[test]
fn spec_direct_numpr_overrides_style_numpr() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "style-numpr-override");
    let paras = common::all_paragraphs(&doc);

    let p1 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("bullets from style"))
        .expect("should find P1 with 'bullets from style' text");

    let p2 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("decimal override"))
        .expect("should find P2 with 'decimal override' text");

    // P1: should have numbering from the style (numId=1, bullets)
    let p1_num = p1
        .numbering
        .as_ref()
        .expect("P1 should have numbering from 'NumberedStyle' style (numId=1, bullets)");
    assert_eq!(
        p1_num.num_id, 1,
        "P1 num_id should be 1 (from style), got {}",
        p1_num.num_id
    );

    // P2: should have numbering from direct numPr (numId=2, decimal)
    let p2_num = p2
        .numbering
        .as_ref()
        .expect("P2 should have numbering — either from style or direct numPr");
    assert_eq!(
        p2_num.num_id, 2,
        "P2 num_id should be 2 (direct numPr overrides style's numId=1 per §17.3.1.19 / §17.7.2), got {}. \
         The direct numPr should win over style numPr.",
        p2_num.num_id
    );

    // Additionally verify that P2's numbering is decimal, not bullet
    assert_eq!(
        p2_num.synthesized_text, "1.",
        "P2 should have decimal numbering '1.' (from numId=2), got '{}'. \
         Direct numPr (decimal) should override style numPr (bullets).",
        p2_num.synthesized_text
    );
}

// ── Dangling numId (parse-totality degradation boundary) ────────────────

/// Build a minimal .docx with an inline `word/numbering.xml` part.
fn make_docx_with_numbering(body_xml: &str, numbering_xml: &str) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );
    let content_types = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/numbering.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"/></Types>"#;
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rIdNum" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering" Target="numbering.xml"/></Relationships>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        zip.start_file("word/numbering.xml", opts).unwrap();
        zip.write_all(numbering_xml.as_bytes()).unwrap();
        zip.finish().unwrap();
    }
    buf
}

/// A paragraph's `numPr` referencing a numId absent from `word/numbering.xml`
/// (dangling numbering reference) is malformed producer output — but Word
/// still opens the document, it just renders the paragraph without a number.
///
/// Per invariant #1 (parse totality), stemma must import the document too,
/// demoting the paragraph to plain text instead of refusing the whole file.
/// This pins the OBSERVABLE DEGRADATION BOUNDARY in `paragraph_from_element`
/// (stemma-engine/src/import.rs): synthesis failure degrades gracefully and
/// is logged, not propagated as an import error.
#[test]
fn dangling_num_id_demotes_paragraph_instead_of_failing_import() {
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="99"/></w:numPr></w:pPr><w:r><w:t>orphaned numbering</w:t></w:r></w:p><w:sectPr/>"#;
    // numbering.xml defines numId=1, not the numId=99 the paragraph references.
    let numbering = r#"<?xml version="1.0" encoding="UTF-8"?>
<w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:abstractNum w:abstractNumId="0">
    <w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%1."/></w:lvl>
  </w:abstractNum>
  <w:num w:numId="1">
    <w:abstractNumId w:val="0"/>
  </w:num>
</w:numbering>"#;
    let bytes = make_docx_with_numbering(body, numbering);

    let runtime = SimpleRuntime::new();
    let import = runtime
        .import_docx(&bytes)
        .expect("dangling numId must not refuse the whole import (invariant #1)");
    let view = runtime.view(&import.doc_handle).expect("view");
    let doc = std::sync::Arc::unwrap_or_clone(view.canonical);
    let paras = common::all_paragraphs(&doc);
    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("orphaned numbering"))
        .expect("paragraph text is preserved");

    assert!(
        p.numbering.is_none(),
        "a dangling numId cannot synthesize a number; the paragraph is demoted \
         to plain text (numbering=None), same as having no numPr at all, got {:?}",
        p.numbering
    );
}
